<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sprintf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;src=&quot;%s&quot;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">esc_url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($script[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;site_scripts_src&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]))</span></span>
